using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search and page fetching capabilities for the research agent.
/// Uses DuckDuckGo's instant answer API (no API key required) for search,
/// and HttpClient for fetching page content.
/// </summary>
public sealed partial class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    public IEnumerable<AIFunction> AsAIFunctions() =>
    [
        AIFunctionFactory.Create(SearchWebAsync, nameof(SearchWebAsync),
            "Search the web for a query and return a list of results with titles, snippets, and URLs."),
        AIFunctionFactory.Create(FetchPageContentAsync, nameof(FetchPageContentAsync),
            "Fetch the text content of a web page at the given URL. Returns the first ~4000 characters of readable text."),
    ];

    [Description("Search the web for a query and return a list of results with titles, snippets, and URLs.")]
    public async Task<IReadOnlyList<SearchResult>> SearchWebAsync(
        [Description("The search query string")] string query,
        CancellationToken cancellationToken = default)
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        var response = await _httpClient.GetFromJsonAsync<DuckDuckGoResponse>(url, cancellationToken);
        var results = new List<SearchResult>();

        if (response is null)
        {
            return results;
        }

        // Add the abstract (main result) if available
        if (!string.IsNullOrWhiteSpace(response.AbstractText))
        {
            results.Add(new SearchResult(
                response.Heading ?? "Top Result",
                response.AbstractText,
                response.AbstractUrl ?? ""));
        }

        // Add related topics
        if (response.RelatedTopics is not null)
        {
            foreach (var topic in response.RelatedTopics)
            {
                if (!string.IsNullOrWhiteSpace(topic.Text) && results.Count < 8)
                {
                    results.Add(new SearchResult(
                        topic.Text.Length > 80 ? topic.Text[..80] + "..." : topic.Text,
                        topic.Text,
                        topic.FirstUrl ?? ""));
                }
            }
        }

        if (results.Count == 0)
        {
            results.Add(new SearchResult(
                "No direct results",
                $"DuckDuckGo instant answers did not return results for '{query}'. Try a more specific query or fetch a known URL directly.",
                ""));
        }

        return results;
    }

    [Description("Fetch the text content of a web page at the given URL.")]
    public async Task<string> FetchPageContentAsync(
        [Description("The full URL of the page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        if (!Uri.TryCreate(url, UriKind.Absolute, out var uri) ||
            (uri.Scheme != "http" && uri.Scheme != "https"))
        {
            return "Error: Invalid URL. Please provide a full http or https URL.";
        }

        try
        {
            var html = await _httpClient.GetStringAsync(uri, cancellationToken);
            var text = StripHtml(html);

            const int maxLength = 4000;
            return text.Length > maxLength
                ? text[..maxLength] + "\n\n[Content truncated at 4000 characters]"
                : text;
        }
        catch (HttpRequestException ex)
        {
            return $"Error fetching page: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        // Remove script and style blocks
        var cleaned = ScriptStyleRegex().Replace(html, " ");
        // Remove HTML tags
        cleaned = TagRegex().Replace(cleaned, " ");
        // Decode common HTML entities
        cleaned = cleaned
            .Replace("&amp;", "&")
            .Replace("&lt;", "<")
            .Replace("&gt;", ">")
            .Replace("&quot;", "\"")
            .Replace("&#39;", "'")
            .Replace("&nbsp;", " ");
        // Collapse whitespace
        cleaned = WhitespaceRegex().Replace(cleaned, " ").Trim();
        return cleaned;
    }

    [GeneratedRegex(@"<(script|style)[^>]*>[\s\S]*?</\1>", RegexOptions.IgnoreCase)]
    private static partial Regex ScriptStyleRegex();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex TagRegex();

    [GeneratedRegex(@"\s{2,}")]
    private static partial Regex WhitespaceRegex();
}

public record SearchResult(string Title, string Snippet, string Url);

// DuckDuckGo instant answer API response shape
internal sealed class DuckDuckGoResponse
{
    [JsonPropertyName("Heading")]
    public string? Heading { get; set; }

    [JsonPropertyName("AbstractText")]
    public string? AbstractText { get; set; }

    [JsonPropertyName("AbstractURL")]
    public string? AbstractUrl { get; set; }

    [JsonPropertyName("RelatedTopics")]
    public List<DuckDuckGoTopic>? RelatedTopics { get; set; }
}

internal sealed class DuckDuckGoTopic
{
    [JsonPropertyName("Text")]
    public string? Text { get; set; }

    [JsonPropertyName("FirstURL")]
    public string? FirstUrl { get; set; }
}

