using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent.
/// Notes are stored in memory and can be added, listed, or exported as a summary.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<Note> _notes = [];

    public IEnumerable<AIFunction> AsAIFunctions() =>
    [
        AIFunctionFactory.Create(SaveNote, nameof(SaveNote),
            "Save a research note with a title and content. Use this to record important findings."),
        AIFunctionFactory.Create(GetAllNotes, nameof(GetAllNotes),
            "Retrieve all saved research notes."),
        AIFunctionFactory.Create(ClearNotes, nameof(ClearNotes),
            "Clear all saved notes to start fresh."),
    ];

    [Description("Save a research note with a title and content.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content/body of the note with the research finding")] string content)
    {
        var note = new Note(title, content, DateTimeOffset.UtcNow);
        _notes.Add(note);
        return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
    }

    [Description("Retrieve all saved research notes.")]
    public IReadOnlyList<Note> GetAllNotes()
    {
        return _notes.AsReadOnly();
    }

    [Description("Clear all saved notes to start fresh.")]
    public string ClearNotes()
    {
        var count = _notes.Count;
        _notes.Clear();
        return $"Cleared {count} note(s).";
    }
}

public record Note(string Title, string Content, DateTimeOffset SavedAt);

