using System.ClientModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build tools -------------------------------------------------------------

using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

var webSearch = new WebSearchTool(httpClient);
var noteTaking = new NoteTakingTool();

var tools = new List<AITool>();
tools.AddRange(webSearch.AsAIFunctions());
tools.AddRange(noteTaking.AsAIFunctions());

// --- Build agent -------------------------------------------------------------

var openAiClient = new OpenAIClient(new ApiKeyCredential(apiKey));
IChatClient chatClient = openAiClient.GetChatClient(modelId).AsIChatClient();

const string instructions = """
    You are a research agent. Your job is to research a topic the user provides by:
    1. Searching the web for relevant information using SearchWebAsync.
    2. Fetching page content from promising URLs using FetchPageContentAsync.
    3. Saving important findings as notes using SaveNote.
    4. After gathering enough information (at least 3-5 notes), retrieving all notes
       with GetAllNotes and producing a well-structured summary.

    Research strategy:
    - Start with a broad search, then narrow down with more specific queries.
    - Always save key facts, statistics, and quotes as notes before summarizing.
    - Cite sources (URLs) in your notes and final summary.
    - If a search returns no results, try rephrasing the query.

    When you have enough information, present a final summary with:
    - An overview of the topic
    - Key findings organized by theme
    - Sources cited
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

// --- Interactive loop --------------------------------------------------------

Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        🔍 Research Agent v1.0           ║");
Console.WriteLine("║  Enter a topic to research, or 'quit'.  ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.ResetColor();

while (true)
{
    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.Green;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        Console.WriteLine("Goodbye!");
        break;
    }

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"Researching \"{topic}\"... (this may take a moment)\n");
    Console.ResetColor();

    try
    {
        var session = await agent.CreateSessionAsync(conversationId: Guid.NewGuid().ToString());

        var response = await agent.RunAsync(
            $"Please research the following topic and provide a comprehensive summary: {topic}",
            session,
            runOptions);

        Console.ForegroundColor = ConsoleColor.Yellow;
        Console.WriteLine("═══ Research Summary ═══");
        Console.ResetColor();

        foreach (var message in response.Messages)
        {
            if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
            {
                Console.WriteLine(message.Text);
            }
        }
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }
}

