var openAiClient = new OpenAIClient(new ApiKeyCredential(apiKey));
IChatClient chatClient = openAiClient.GetChatClient(modelId).AsIChatClient();

const string instructions = """
    You are a research agent. Your job is to research a topic the user provides by:
    1. Searching the web for relevant information using SearchWebAsync.
    2. Fetching page content from promising URLs using FetchPageContentAsync.
    3. Saving important findings as notes using SaveNote.
    4. After gathering enough information (at least 3-5 notes), retrieving all notes
       with GetAllNotes and producing a well-structured summary.

    Research strategy:
    - Start with a broad search, then narrow down with more specific queries.
    - Always save key facts, statistics, and quotes as notes before summarizing.
    - Cite sources (URLs) in your notes and final summary.
    - If a search returns no results, try rephrasing the query.

    When you have enough information, present a final summary with:
    - An overview of the topic
    - Key findings organized by theme
    - Sources cited
    """;

var agent = new ChatClientAgent(
